function c(t){if(!t&&t!==0)return"-";const e=["B","KB","MB","GB","TB","PB"];let n=0,r=t;for(;r>=1024&&n<e.length-1;)r/=1024,n++;return`${r.toFixed(r>=100||n===0?0:1)} ${e[n]}`}function a(t){return`${c(t)}/s`}function l(t){if(!t)return"-";const e=Math.floor(t/86400),n=Math.floor(t%86400/3600),r=Math.floor(t%3600/60);return e>0?`${e}天 ${n}小时`:n>0?`${n}小时 ${r}分`:`${r}分`}function m(t){return`${(t||0).toFixed(1)}%`}function $(t){return t?new Date(t*1e3).toLocaleString():"-"}function h(t){return t>=90?"crit":t>=70?"warn":""}function g(t){if(!t||!t.length)return{text:"",cores:0};const e=new Map;let n=0;for(const o of t){const f=String(o).match(/^(.*?)\s*(\d+)\s+Cores?$/i);if(f){const i=f[1].trim(),u=Number(f[2]);e.set(i,(e.get(i)||0)+u),n+=u}else e.set(String(o),e.get(String(o))||0)}return{text:[...e.entries()].map(([o,f])=>f?o?`${o} · ${f} 核`:`${f} 核`:o).join(" / "),cores:n}}const s=["#3b82f6","#22c55e","#eab308","#ef4444","#a855f7","#06b6d4","#f97316","#ec4899"];function d(t){let e=0;for(let n=0;n<t.length;n++)e=e*31+t.charCodeAt(n)>>>0;return s[e%s.length]}export{c as a,h as b,a as c,l as d,g as e,m as f,$ as g,d as t};
